# ThemeProvider

## Import

```jsx live=false
import { ThemeProvider } from '@node-real/bee';
```

## Usage

```jsx live=false
import { ThemeProvider } from '@node-real/bee';

const theme = {
  config: {
    useSystemColorMode: false,
    initialColorMode: 'light',
  },
  styles: {
    global: {
      body: {
        fontSize: '1rem',
        bg: 'bg.bottom',
        color: 'readable.normal',
      },
    },
  },
};

function App() {
  return <ThemeProvider theme={theme}>{/* Components */}</ThemeProvider>;
}
```

